solution_code:
#include <iostream>

int main()
{
    int length = 0;
    int width = 0;
    std::cin >> length >> width;

    int area = length * width;
    int perimeter = 2 * length + 2 * width;

    std::cout << "Area: " << area << '\n';
    std::cout << "Perimeter: " << perimeter << '\n';

    return 0;
}

